class Solution:
   def solve(self, nums: list[int]) -> bool:
      n = len(nums)
      for i in range(n):
         for j in range(n - 1):
            if nums[j] > nums[j + 1]:
               nums[j], nums[j + 1] = nums[j + 1], nums[j]
      return nums == sorted(nums)

def main():
   from sys import stdin
   input = stdin.readline
   n = int(input())
   nums = list(map(int, input().split()))
   s = Solution()
   print('YES' if s.solve(nums) else 'NO')

